function printResult(result: unknown, format: string) {
	const wrapped = createCallResult(result);
	const rawPayload = unwrapRawPayload(wrapped.raw);
	switch (format) {
		case 'json': {
			const json = wrapped.json();
			if (json !== null) {
				console.log(JSON.stringify(json, null, 2));
				return;
			}
			console.log(JSON.stringify(rawPayload, null, 2));
			return;
		}
		case 'markdown': {
			const markdown = wrapped.markdown();
			if (markdown) {
				console.log(markdown);
				return;
			}
			break;
		}
		case 'raw': {
			console.log(JSON.stringify(rawPayload, null, 2));
			return;
		}
	}
	const text = wrapped.text();
	if (text) {
		console.log(text);
	} else {
		console.log(JSON.stringify(rawPayload, null, 2));
	}
}

function unwrapRawPayload(value: unknown): unknown {
	if (value && typeof value === 'object' && 'raw' in value) {
		return (value as { raw: unknown }).raw;
	}
	return value;
}

function parseArrayOption(value: string, itemType: 'string' | 'number' | 'boolean' | 'json') {
	const trimmed = value.trim();
	if (trimmed.startsWith('[')) {
		const parsed = JSON.parse(trimmed);
		if (!Array.isArray(parsed)) {
			throw new Error('Expected a JSON array.');
		}
		return parsed;
	}
	if (itemType === 'json') {
		const parsed = JSON.parse('[' + value + ']');
		if (!Array.isArray(parsed)) {
			throw new Error('Expected JSON array items.');
		}
		return parsed;
	}
	const values = value.split(',').map((entry) => entry.trim());
	if (itemType === 'number') {
		return values.map((entry) => parseFloat(entry));
	}
	if (itemType === 'boolean') {
		return values.map((entry) => entry !== 'false');
	}
	return values;
}

