async function invokeWithTimeout<T>(call: Promise<T>, timeout: number): Promise<T> {
	if (!Number.isFinite(timeout) || timeout <= 0) {
		return await call;
	}
	let timer: ReturnType<typeof setTimeout> | undefined;
	try {
		return await Promise.race([
			call,
			new Promise<never>((_, reject) => {
				timer = setTimeout(() => {
					reject(new Error('Call timed out after ' + timeout + 'ms.'));
				}, timeout);
			}),
		]);
	} finally {
		if (timer) {
			clearTimeout(timer);
		}
	}
}

function parseGeneratedDaemonInvocation(rawArgs: string[]): { args: string[]; configPath: string; rootDir?: string } | null {
	const args = [...rawArgs];
	let configPath: string | undefined;
	let rootDir: string | undefined;
	while (args.length > 0) {
		const token = args[0];
		if (token === '--config') {
			args.shift();
			configPath = args.shift();
			continue;
		}
		if (token?.startsWith('--config=')) {
			args.shift();
			configPath = token.slice('--config='.length);
			continue;
		}
		if (token === '--root') {
			args.shift();
			rootDir = args.shift();
			continue;
		}
		if (token?.startsWith('--root=')) {
			args.shift();
			rootDir = token.slice('--root='.length);
			continue;
		}
		break;
	}
	if (args[0] !== 'daemon') {
		return null;
	}
	if (!configPath) {
		throw new Error('Generated daemon invocation is missing --config.');
	}
	return { args: args.slice(1), configPath, rootDir };
}

async function runCli(): Promise<void> {
	const args = process.argv.slice(2);
	const daemonInvocation = parseGeneratedDaemonInvocation(args);
	if (daemonInvocation) {
		await handleDaemonCli([...daemonInvocation.args], {
			configPath: daemonInvocation.configPath,
			configExplicit: true,
			rootDir: daemonInvocation.rootDir,
		});
		return;
	}
	if (args.length === 0) {
		program.outputHelp();
		return;
	}
	await program.parseAsync(process.argv);
}

